import java.util.Arrays;

public int threeSumMulti(int[] arr, int target) {
    int MOD = 1000000007;
    long ans = 0;

    Arrays.sort(arr);
    int n = arr.length;

    for (int i = 0; i < n - 2; ++i) {
        int j = i + 1, k = n - 1;
        while (j < k) {
            int sum = arr[i] + arr[j] + arr[k];
            if (sum > target) {
                k--;
            } else if (sum < target) {
                j++;
            } else {
                if (arr[j] != arr[k]) {
                    int left_count = 1, right_count = 1;

                    while (j < n-1 && arr[j] == arr[j + 1]){
                        left_count++; 
                        j++;
                    }
                    while (k > 0 && arr[k] == arr[k - 1]){
                        right_count++;
                        k--;
                    }

                    ans += (long) left_count * right_count;
                    ans %= MOD;
                    j++; k--;
                } else {
                    ans += (long) (k - j + 1) * (k - j) / 2;
                    ans %= MOD;
                    break;
                }
            }
        }
    }

    return (int) ans;
}
```

    1. Sort the array.
2. Iterate through the array using 3 pointers (i, j, k) with i starting from the first element, j starting from the second, and k starting from the last one. Make sure i < j < k.
3. Find the sum of elements pointed by i, j and k. If the sum is greater than the target, decrement k. If the sum is less than the target, increment j.
4. Calculate the number of combinations when the sum is equal to the target. Then, update the pointers as required.
5. Continue until i < j < k is not satisfied.
6. Return the result modulo 10^9 + 7.
